def count_peaks(data):
    n = len(data)
    if n < 3:
        return 0

    count = 0
    i = 1  # start from second element

    while i < n - 1:
        # Check if current element is greater than left neighbor
        if data[i] > data[i - 1]:
            # Check if it's a single peak
            if data[i] > data[i + 1]:
                count += 1
                i += 1
            # Check if it's the start of a plateau
            elif data[i] == data[i + 1]:
                # Find the end of the plateau
                j = i + 1
                while j < n - 1 and data[j] == data[i]:
                    j += 1
                # Check if plateau is a peak (greater than both outer neighbors)
                if data[i] > data[i - 1] and data[j - 1] > data[j]:
                    count += 1
                i = j  # skip past the plateau
            else:
                i += 1
        else:
            i += 1

    return count
```

