def find_kth_unique(nums, k):
    # Step 1: Count frequencies manually
    freq = {}
    for num in nums:
        freq[num] = freq.get(num, 0) + 1

    # Step 2: Collect unique elements (appear exactly once)
    unique_vals = [num for num, count in freq.items() if count == 1]

    if k > len(unique_vals):
        return None

    # Step 3: Use quickselect to find k-th smallest (0-indexed: k-1)
    def quickselect(arr, left, right, k_smallest):
        if left == right:
            return arr[left]

        # Choose pivot (median-of-three to avoid worst-case)
        mid = (left + right) // 2
        pivot_val = sorted([arr[left], arr[mid], arr[right]])[1]

        # Partition
        pivot_index = partition(arr, left, right, pivot_val)

        if k_smallest == pivot_index:
            return arr[k_smallest]
        elif k_smallest < pivot_index:
            return quickselect(arr, left, pivot_index - 1, k_smallest)
        else:
            return quickselect(arr, pivot_index + 1, right, k_smallest)

    def partition(arr, left, right, pivot_val):
        # Move pivot to end
        pivot_idx = left
        while arr[pivot_idx] != pivot_val:
            pivot_idx += 1
        arr[pivot_idx], arr[right] = arr[right], arr[pivot_idx]

        store_index = left
        for i in range(left, right):
            if arr[i] < pivot_val:
                arr[store_index], arr[i] = arr[i], arr[store_index]
                store_index += 1
        arr[store_index], arr[right] = arr[right], arr[store_index]
        return store_index

    return quickselect(unique_vals, 0, len(unique_vals) - 1, k - 1)
